/**
 * Level Service
 * Service quản lý levels, subjects, và quizzes theo hierarchy mới
 */

import { getAllLevels, getLevelById, getSubjectsForLevel } from '../models/level.js';
import { QUIZ_TYPES } from '../models/level.js';
import { getAllCachedQuizzes, getCachedQuiz } from './storageService.js';

/**
 * Load danh sách levels
 */
export const loadLevels = async () => {
  // Có thể load từ cloud hoặc dùng local config
  return getAllLevels();
};

/**
 * Load subjects cho một level
 */
export const loadSubjectsForLevel = async (levelId) => {
  // Có thể load từ cloud hoặc dùng local config
  return getSubjectsForLevel(levelId);
};

/**
 * Load quiz list với filters
 * @param {Object} filters - { levelId, subjectId, quizType, creatorId }
 */
export const loadQuizList = async (filters = {}) => {
  try {
    // Load từ IndexedDB local (đã cache)
    const quizzes = await getAllCachedQuizzes();
    
    // Apply filters
    let filtered = quizzes;
    
    if (filters.levelId) {
      filtered = filtered.filter(q => q.levelId === filters.levelId);
    }
    
    if (filters.subjectId) {
      filtered = filtered.filter(q => q.subjectId === filters.subjectId);
    }
    
    if (filters.quizType) {
      filtered = filtered.filter(q => q.quizType === filters.quizType);
    }
    
    if (filters.creatorId) {
      filtered = filtered.filter(q => q.creatorId === filters.creatorId);
    }
    
    // Sort by usage count (popularity) or created date
    filtered.sort((a, b) => {
      if (filters.sortBy === 'usage') {
        return (b.usageCount || 0) - (a.usageCount || 0);
      }
      if (filters.sortBy === 'rating') {
        return (b.rating || 0) - (a.rating || 0);
      }
      return (b.createdAt || 0) - (a.createdAt || 0);
    });
    
    return filtered;
  } catch (error) {
    console.error('Error loading quiz list:', error);
    return [];
  }
};

