/**
 * Search quizzes với keyword
 */
export const searchQuizzes = async (keyword, filters = {}) => {
  try {
    const quizzes = await loadQuizList(filters);
    
    if (!keyword || !keyword.trim()) {
      return quizzes;
    }
    
    const lowerKeyword = keyword.toLowerCase();
    return quizzes.filter(quiz => {
      return (
        quiz.title?.toLowerCase().includes(lowerKeyword) ||
        quiz.description?.toLowerCase().includes(lowerKeyword) ||
        quiz.creatorName?.toLowerCase().includes(lowerKeyword) ||
        (quiz.tags && Array.isArray(quiz.tags) && 
         quiz.tags.some(tag => tag.toLowerCase().includes(lowerKeyword)))
      );
    });
  } catch (error) {
    console.error('Error searching quizzes:', error);
    return [];
  }
};



